import { createOurContext, theirContext } from "../context/mod.ts";
import { type Tests, testing } from "./testing.ts";

// The bytes for these tests were generated by the last version of GAVRAsm
// that I could get hold of.

const tests: Tests = [
    [["LDS", ["R30",  "1024"]], [0x91, 0xe0, 0x04, 0x00]],
    [["STS", ["4096", "R8"  ]], [0x92, 0x80, 0x10, 0x00]],
];

const reducedCoreTests: Tests = [
    [["LDS", ["R30", "120"]], [0xa7, 0xe8]],
    [["STS", ["126", "R18"]], [0xaf, 0x2e]]
];

testing(tests, createOurContext(theirContext()));

const context = createOurContext(theirContext());
context.reducedCore = true;
testing(reducedCoreTests, context);
